// Minimal ERC-721 balanceOf ABI used by F2Submit's eligibility filter.
const _erc721BalanceOfAbi = [{
  type: "function",
  name: "balanceOf",
  stateMutability: "view",
  inputs: [{ type: "address", name: "owner" }],
  outputs: [{ type: "uint256" }],
}];

// ABI fragments for live token-registry reads (icon + holder count).
const _tokenMetaAbi = [
  { type: "function", name: "totalSupply", stateMutability: "view", inputs: [], outputs: [{ type: "uint256" }] },
  { type: "function", name: "contractURI", stateMutability: "view", inputs: [], outputs: [{ type: "string" }] },
];

// Map our internal chain label → wagmi chainId.
function _chainIdFor(chainLabel) {
  return chainLabel === "Arbitrum" ? 42161 : 1;
}

// Rewrite an IPFS or http URL into a browser-loadable image URL. Falls
// back to passing the string through unchanged for http(s) and data:.
function _ipfsToHttp(u) {
  if (!u || typeof u !== "string") return null;
  if (u.startsWith("ipfs://ipfs/")) return "https://ipfs.io/ipfs/" + u.slice(12);
  if (u.startsWith("ipfs://")) return "https://ipfs.io/ipfs/" + u.slice(7);
  return u;
}

// ERC-20 icons via TrustWallet's CDN — pattern matches their assets
// repo (mainnet/Arbitrum). Returns null when address looks invalid.
function _erc20IconUrl(token) {
  if (!token || !token.address || !/^0x[a-fA-F0-9]{40}$/.test(token.address)) return null;
  const chainSlug = token.chain === "Arbitrum" ? "arbitrum" : "ethereum";
  return "https://raw.githubusercontent.com/trustwallet/assets/master/blockchains/" + chainSlug + "/assets/" + token.address + "/logo.png";
}

// Module-level cache so we don't re-fetch the same IPFS metadata on
// every re-render or component remount. Map: contractURI → image URL.
const _iconMetaCache = new Map();

// Hook: resolve a registered token's icon URL via on-chain contractURI
// (for ERC-721/-1155) or TrustWallet CDN (for ERC-20). Returns null while
// loading or when nothing usable was found. Browser-only — the on-chain
// read goes through wagmi's configured RPC.
function _useTokenIcon(token) {
  const isErc20 = token && token.kind === "ERC-20";
  const isContractKind = token && (token.kind === "ERC-721" || token.kind === "ERC-1155");
  const { data: contractUri } = wagmi.useReadContract({
    address: token && token.address,
    abi: _tokenMetaAbi,
    functionName: "contractURI",
    chainId: _chainIdFor(token && token.chain),
    query: { enabled: !!(token && token.address && isContractKind) },
  });
  const [resolved, setResolved] = useState(null);
  useEffect(() => {
    if (isErc20) {
      setResolved(_erc20IconUrl(token));
      return;
    }
    if (!contractUri || typeof contractUri !== "string") {
      setResolved(null);
      return;
    }
    // Some contracts return inline data: URLs that ARE the JSON metadata
    // directly. Handle both that and ipfs:// / https:// pointers.
    const cacheKey = String(contractUri);
    if (_iconMetaCache.has(cacheKey)) {
      setResolved(_iconMetaCache.get(cacheKey));
      return;
    }
    let cancelled = false;
    (async () => {
      try {
        let metaText = "";
        if (cacheKey.startsWith("data:application/json")) {
          // data:application/json;base64,... OR data:application/json,...
          const comma = cacheKey.indexOf(",");
          if (comma < 0) return;
          const isB64 = cacheKey.slice(0, comma).includes("base64");
          metaText = isB64 ? atob(cacheKey.slice(comma + 1)) : decodeURIComponent(cacheKey.slice(comma + 1));
        } else {
          const url = _ipfsToHttp(cacheKey);
          if (!url) return;
          const r = await fetch(url, { mode: "cors" });
          if (!r.ok) return;
          metaText = await r.text();
        }
        const meta = JSON.parse(metaText);
        const img = meta && (meta.image || meta.image_url || meta.icon || null);
        const out = img ? _ipfsToHttp(img) : null;
        _iconMetaCache.set(cacheKey, out);
        if (!cancelled) setResolved(out);
      } catch { /* swallow — fallback to gradient */ }
    })();
    return () => { cancelled = true; };
  }, [contractUri, isErc20, token && token.address, token && token.chain]);
  return resolved;
}

// Hook: live holder count via totalSupply(). Accurate for 1-NFT-per-wallet
// badges; for ERC-1155 / ERC-20 returns null and the row falls back to —.
function _useTokenHolderCount(token) {
  const isCountable = token && (token.kind === "ERC-721");
  const { data } = wagmi.useReadContract({
    address: token && token.address,
    abi: _tokenMetaAbi,
    functionName: "totalSupply",
    chainId: _chainIdFor(token && token.chain),
    query: { enabled: !!(token && token.address && isCountable) },
  });
  if (data === undefined || data === null) return null;
  try { return Number(data); } catch { return null; }
}

